// Parse + decode JWT + build search SQL
const headers = $('Webhook Search').first().json.headers || {};
const body = $('Webhook Search').first().json.body || {};

const authHeader = headers.authorization || headers.Authorization || '';
const token = authHeader.replace('Bearer ', '');

if (!token) {
  return [{ json: { error: true, message: 'Thiếu token xác thực', status: 401 } }];
}

let userId = null;
try {
  const payload = JSON.parse(Buffer.from(token.split('.')[1], 'base64').toString());
  userId = payload.sub;
  if (!userId) throw new Error('Không có user ID');
} catch (e) {
  return [{ json: { error: true, message: 'Token không hợp lệ', status: 401 } }];
}

// Build WHERE clauses
let conditions = [];

// Mặc định ẩn superseded/archived
if (body.include_superseded !== true) {
  conditions.push("status NOT IN ('superseded', 'archived')");
}

if (body.document_type) conditions.push(`document_type = '${body.document_type}'::document_type`);
if (body.source_type) conditions.push(`source_type = '${body.source_type}'::source_type`);
if (body.language_code) conditions.push(`language_code = '${body.language_code}'::language_code`);
if (body.status) conditions.push(`status = '${body.status}'::document_status`);
if (body.equipment_type) conditions.push(`equipment_type = '${body.equipment_type.replace(/'/g, "''")}'`);
if (body.equipment_code) conditions.push(`equipment_code = '${body.equipment_code.replace(/'/g, "''")}'`);
if (body.owner_department) conditions.push(`owner_department = '${body.owner_department.replace(/'/g, "''")}'`);
if (body.translation_status) conditions.push(`translation_status = '${body.translation_status}'::translation_status`);

// Keyword search
if (body.keyword) {
  const kw = body.keyword.replace(/'/g, "''");
  conditions.push(`(document_code ILIKE '%${kw}%' OR document_title ILIKE '%${kw}%')`);
}

const whereClause = conditions.length > 0 ? 'WHERE ' + conditions.join(' AND ') : '';
const limit = Math.min(Math.max(parseInt(body.limit) || 50, 1), 100);
const offset = Math.max(parseInt(body.offset) || 0, 0);

const sql = `SELECT id, document_group_id, document_code, document_title, document_type, language_code, source_type, version, status, approved_for_ai_use, translation_status, is_ai_translated, owner_department, equipment_type, equipment_code, file_name, file_hash, page_count, chunk_count, uploaded_at, reviewed_at, approved_at, effective_date FROM documents ${whereClause} ORDER BY document_code ASC, version DESC LIMIT ${limit} OFFSET ${offset};`;

const countSql = `SELECT count(*) as total FROM documents ${whereClause};`;

return [{ json: { error: false, search_sql: sql, count_sql: countSql, filters: body, limit, offset } }];

const docs = $input.all().map(item => item.json);
const meta = $('Parse + Build SQL').first().json;

// Nếu query trả rỗng, docs[0] có thể là object rỗng
const validDocs = docs.filter(d => d.id);

return [{ json: {
  success: true,
  documents: validDocs,
  total_count: validDocs.length,
  limit: meta.limit,
  offset: meta.offset,
  filters_applied: meta.filters
}}];
